class Solution {
    public int getMinSwaps(String num, int k) {
        char[] chars = num.toCharArray();
        int n = chars.length;
        int[] count = new int[10];
        for (char c : chars) {
            count[c - '0']++;
        }
        int[] res = new int[n];
        int idx = 0;
        for (int i = 9; i >= 0; i--) {
            while (count[i]-- > 0) {
                res[idx++] = i;
            }
        }
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) {
            arr[i] = chars[i] - '0';
        }
        Arrays.sort(arr);
        int ans = 0;
        for (int i = 0; i < n; i++) {
            if (arr[i] != res[i]) {
                int j = i + 1;
                while (j < n && arr[j] <= arr[i]) {
                    j++;
                }
                ans += j - i - 1;
                int temp = arr[i];
                arr[i] = arr[j - 1];
                arr[j - 1] = temp;
            }
        }
        int cnt = 0;
        for (int i = 0; i < n; i++) {
            if (chars[i] != (char) (res[i] + '0')) {
                cnt++;
            }
        }
        k--;
        while (k-- > 0) {
            cnt++;
        }
        return cnt;
    }
}
